#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>
#include <cuda_runtime.h>

#define TOL      (0.001)
#define STR_SIZE (256)
#define MAX_PD   (3.0e6)

#define PRECISION    0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI         100

#define FACTOR_CHIP  0.5

#define WG_SIZE_X (64)
#define WG_SIZE_Y (4)

float t_chip      = 0.0005f;
float chip_height = 0.016f;
float chip_width  = 0.016f;
float amb_temp    = 80.0f;

extern "C" __global__ void hotspotOpt1(float *p, float* tIn, float *tOut, float sdc,
                                       int nx, int ny, int nz,
                                       float ce, float cw,
                                       float cn, float cs,
                                       float ct, float cb,
                                       float cc);

static void tvsub(struct timeval *x, struct timeval *y, struct timeval *t)
{
    t->tv_sec = x->tv_sec - y->tv_sec;
    t->tv_usec = x->tv_usec - y->tv_usec;
    if (t->tv_usec < 0) {
        --t->tv_sec;
        t->tv_usec += 1000000;
    }
}

static void fatal(char *s)
{
    fprintf(stderr, "Error: %s\n", s);
}

static int output_device_info(int device_id)
{
    cudaDeviceProp prop;
    cudaError_t err = cudaGetDeviceProperties(&prop, device_id);
    if (err != cudaSuccess) {
        printf("Error: Failed to access device info!\n");
        return EXIT_FAILURE;
    }

    printf(" \n Device is  %s \n", prop.name);
    printf(" %s \n", "NVIDIA Corporation");
    return 0;
}

static void readinput(float *vect, int grid_rows, int grid_cols, int layers, char *file)
{
    int i, j, k;
    FILE *fp;
    char str[STR_SIZE];
    float val;

    if ((fp = fopen(file, "r")) == 0)
        fatal((char*)"The file was not opened");

    for (i = 0; i <= grid_rows - 1; i++)
        for (j = 0; j <= grid_cols - 1; j++)
            for (k = 0; k <= layers - 1; k++) {
                if (fgets(str, STR_SIZE, fp) == NULL) fatal((char*)"Error reading file\n");
                if (feof(fp)) fatal((char*)"not enough lines in file");
                if ((sscanf(str, "%f", &val) != 1)) fatal((char*)"invalid file format");
                vect[i * grid_cols + j + k * grid_rows * grid_cols] = val;
            }

    fclose(fp);
}

static void writeoutput(float *vect, int grid_rows, int grid_cols, int layers, char *file)
{
    int i, j, k, index = 0;
    FILE *fp;
    char str[STR_SIZE];

    if ((fp = fopen(file, "w")) == 0)
        printf("The file was not opened\n");

    for (i = 0; i < grid_rows; i++)
        for (j = 0; j < grid_cols; j++)
            for (k = 0; k < layers; k++) {
                sprintf(str, "%d\t%g\n", index, vect[i * grid_cols + j + k * grid_rows * grid_cols]);
                fputs(str, fp);
                index++;
            }

    fclose(fp);
}

static void computeTempCPU(float *pIn, float* tIn, float *tOut,
                           int nx, int ny, int nz, float Cap,
                           float Rx, float Ry, float Rz,
                           float dt, float amb_temp, int numiter)
{
    float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;

    cc = 1.0f - (2.0f * ce + 2.0f * cn + 3.0f * ct);

    int c, w, e, n, s, b, t;
    int x, y, z;
    int i = 0;
    do {
        for (z = 0; z < nz; z++)
            for (y = 0; y < ny; y++)
                for (x = 0; x < nx; x++) {
                    c = x + y * nx + z * nx * ny;

                    w = (x == 0) ? c : c - 1;
                    e = (x == nx - 1) ? c : c + 1;
                    n = (y == 0) ? c : c - nx;
                    s = (y == ny - 1) ? c : c + nx;
                    b = (z == 0) ? c : c - nx * ny;
                    t = (z == nz - 1) ? c : c + nx * ny;

                    tOut[c] = tIn[c] * cc + tIn[n] * cn + tIn[s] * cs + tIn[e] * ce + tIn[w] * cw +
                              tIn[t] * ct + tIn[b] * cb + (dt / Cap) * pIn[c] + ct * amb_temp;
                }
        float *temp = tIn;
        tIn = tOut;
        tOut = temp;
        i++;
    } while (i < numiter);
}

static float accuracy(float *arr1, float *arr2, int len)
{
    float err = 0.0f;
    for (int i = 0; i < len; i++)
        err += (arr1[i] - arr2[i]) * (arr1[i] - arr2[i]);
    return sqrtf(err / len);
}

static void usage(int argc, char **argv)
{
    fprintf(stderr, "Usage: %s <-n rows/cols> <-l layers> <-i iterations> <-f powerFile tempFile outputFile> [-p platform] [-d device]\n", argv[0]);
    fprintf(stderr, "\t<rows/cols>  - number of rows/cols in the grid (positive integer)\n");
    fprintf(stderr, "\t<layers>  - number of layers in the grid (positive integer)\n");
    fprintf(stderr, "\t<iteration> - number of iterations\n");
    fprintf(stderr, "\t<powerFile>  - name of the file containing the initial power values of each cell\n");
    fprintf(stderr, "\t<tempFile>  - name of the file containing the initial temperature values of each cell\n");
    fprintf(stderr, "\t<outputFile - output file\n");
    exit(1);
}

int main(int argc, char** argv)
{
    char *pfile = NULL, *tfile = NULL, *ofile = NULL;
    int iterations = 0;
    int numCols = 0;
    int numRows = 0;
    int layers = 0;

    int platform_id_inuse = 0;
    int device_id_inuse = 0;

    for (int cur_arg = 1; cur_arg < argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-h") == 0) {
            usage(argc, argv);
        } else if (strcmp(argv[cur_arg], "-n") == 0) {
            if (argc >= cur_arg + 1) {
                numCols = numRows = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (strcmp(argv[cur_arg], "-l") == 0) {
            if (argc >= cur_arg + 1) {
                layers = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (strcmp(argv[cur_arg], "-i") == 0) {
            if (argc >= cur_arg + 1) {
                iterations = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (strcmp(argv[cur_arg], "-f") == 0) {
            if (argc >= cur_arg + 3) {
                pfile = argv[cur_arg + 1];
                tfile = argv[cur_arg + 2];
                ofile = argv[cur_arg + 3];
                cur_arg += 3;
            }
        } else if (strcmp(argv[cur_arg], "-p") == 0) {
            if (argc >= cur_arg + 1) {
                platform_id_inuse = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (strcmp(argv[cur_arg], "-d") == 0) {
            if (argc >= cur_arg + 1) {
                device_id_inuse = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
    }

    if (numCols == 0 || layers == 0 || iterations == 0 || pfile == NULL) {
        usage(argc, argv);
    }

    (void)platform_id_inuse;

    float dx = chip_height / numRows;
    float dy = chip_width / numCols;
    float dz = t_chip / layers;

    float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * dx * dy;
    float Rx = dy / (2.0f * K_SI * t_chip * dx);
    float Ry = dx / (2.0f * K_SI * t_chip * dy);
    float Rz = dz / (K_SI * dx * dy);

    float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    float dt = PRECISION / max_slope;

    float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;
    cc = 1.0f - (2.0f * ce + 2.0f * cn + 3.0f * ct);

    int size = numCols * numRows * layers;
    int count = size;

    float *tIn = (float*)calloc(size, sizeof(float));
    float *pIn = (float*)calloc(size, sizeof(float));
    float *tempCopy = (float*)malloc(size * sizeof(float));
    float *tempOut = (float*)calloc(size, sizeof(float));

    readinput(tIn, numRows, numCols, layers, tfile);
    readinput(pIn, numRows, numCols, layers, pfile);
    memcpy(tempCopy, tIn, size * sizeof(float));

#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end;
    struct timeval tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
          d2h_time = 0, close_time = 0, total_time = 0;
    gettimeofday(&tv_total_start, NULL);
#endif

    int num_devices = 0;
    cudaError_t cerr = cudaGetDeviceCount(&num_devices);
    if (cerr != cudaSuccess) {
        printf("ERROR: cudaGetDeviceCount failed\n");
        return EXIT_FAILURE;
    }
    printf("num_devices = %d\n", num_devices);
    if (device_id_inuse > num_devices - 1 || device_id_inuse < 0) {
        printf("Invalid Device Number\n");
        return EXIT_FAILURE;
    }
    cudaSetDevice(device_id_inuse);
    output_device_info(device_id_inuse);

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    float *d_a = NULL, *d_b = NULL, *d_c = NULL;
    cudaMalloc((void**)&d_a, sizeof(float) * count);
    cudaMalloc((void**)&d_b, sizeof(float) * count);
    cudaMalloc((void**)&d_c, sizeof(float) * count);

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    if (!d_a || !d_b || !d_c) {
        printf("Error: Failed to allocate device memory!\n");
        exit(1);
    }

#ifdef TIMING
    struct timeval t1, t2;
    gettimeofday(&t1, NULL);
#endif
    cudaMemcpy(d_a, tIn, sizeof(float) * count, cudaMemcpyHostToDevice);
    cudaMemcpy(d_b, pIn, sizeof(float) * count, cudaMemcpyHostToDevice);
    cudaMemcpy(d_c, tempOut, sizeof(float) * count, cudaMemcpyHostToDevice);
#ifdef TIMING
    gettimeofday(&t2, NULL);
    tvsub(&t2, &t1, &tv);
    h2d_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    dim3 block(WG_SIZE_X, WG_SIZE_Y);
    dim3 grid((numCols + block.x - 1) / block.x, (numRows + block.y - 1) / block.y);

    for (int j = 0; j < iterations; j++) {
#ifdef TIMING
        gettimeofday(&t1, NULL);
#endif
        hotspotOpt1<<<grid, block>>>(d_b, d_a, d_c, stepDivCap,
                                     numCols, numRows, layers,
                                     ce, cw, cn, cs, ct, cb, cc);
        cudaDeviceSynchronize();

        float *temp = d_a;
        d_a = d_c;
        d_c = temp;
#ifdef TIMING
        gettimeofday(&t2, NULL);
        tvsub(&t2, &t1, &tv);
        kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif
    }

#ifdef TIMING
    gettimeofday(&t1, NULL);
#endif
    cudaMemcpy(tempOut, d_c, sizeof(float) * count, cudaMemcpyDeviceToHost);
#ifdef TIMING
    gettimeofday(&t2, NULL);
    tvsub(&t2, &t1, &tv);
    d2h_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    gettimeofday(&tv_close_start, NULL);
#endif

    cudaFree(d_a);
    cudaFree(d_b);
    cudaFree(d_c);

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    float *answer = (float*)calloc(size, sizeof(float));
    computeTempCPU(pIn, tempCopy, answer, numCols, numRows, layers, Cap, Rx, Ry, Rz, dt, amb_temp, iterations);
    float acc = accuracy(tempOut, answer, numRows * numCols * layers);
    printf("Accuracy: %e\n", acc);

    writeoutput(tempOut, numRows, numCols, layers, ofile);

    free(tIn);
    free(pIn);
    free(tempCopy);
    free(tempOut);
    free(answer);

    return 0;
}
